class AllOne {
public:
    AllOne() {
        maxCount = 0;
        minCount = 0;
    }

    void inc(string key) {
        if (keyCount.find(key) == keyCount.end()) {
            keyCount[key] = 1;
            countKeys[1].insert(key);
            if (minCount == 0 || minCount > 1) {
