            countKeys[count + 1].insert(key);
            if (count + 1 > maxCount) {
                maxCount = count + 1;
            }
        }
    }

    void dec(string key) {
        int count = keyCount[key];
        countKeys[count].erase(key);
        if (count == maxCount && countKeys[count].empty()) {
            maxCount--;
        }
        keyCount[key]--;
        if (keyCount[key] == 0) {
            keyCount.erase(key);
        } else {
            countKeys[count - 1].insert(key);
            if (count == minCount) {
                minCount--;
            }
        }
        if (countKeys[minCount].empty()) {
            minCount++;
        }
    }

    string getMaxKey() {
        if (maxCount == 0) {
            return "";
        }
        return *countKeys[maxCount].begin();
    }

    string getMinKey() {
        if (minCount == 0) {
            return "";
        }
        return *countKeys[minCount].begin();
    }

private:
